'use strict';

const vq=require('./vq.js');
const http=require('http');


function translate(q,tl='zh-CN') {
  return new Promise((resolve,reject)=>{
    if(!q) return resolve(null);
    let url='http://translate.google.cn/translate_a/single?client=gtx&dt=t&ie=UTF-8&oe=UTF-8&sl=auto&tl='+tl+'&q='+encodeURIComponent(q);
    http.get(url, function(res){
      if(res.statusCode!==200) resolve(null);
      res.on('data',d=>{
        resolve(d.toString('utf8'));
    }).on('error',e=>resolve(null));
  });  
  });
}

module.exports=translate;
